export const CATEGORIES = [
  'All', 'Piano', 'Organ', 'Strings', 'Choir', 'Guitar', 'Bass', 'Brass', 'Flute', 'Indian', 'World', 'Drums', 'Pad', 'Percussion', 'SFX', 'Arpeggio', 'Custom'
];

export function usePresets() {
  const [presets, setPresets] = useState(() => {
    const saved = localStorage.getItem('midi_voices');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Automatically migrate / update existing presets to include voiceNo if missing
        return parsed.map(preset => {
          if (preset.voiceNo === undefined) {
            const match = DEFAULT_PRESETS.find(dp => 
              dp.name.toLowerCase() === preset.name.toLowerCase() ||
              (dp.msb === preset.msb && dp.lsb === preset.lsb && dp.program === preset.program && dp.msb !== null)
            );
            return {
              ...preset,
              voiceNo: match ? match.voiceNo : null
            };
          }
          return preset;
        });
      } catch (e) {
        console.error('Error parsing presets from localStorage', e);
      }
    }
    return DEFAULT_PRESETS;
  });

  useEffect(() => {
    localStorage.setItem('midi_voices', JSON.stringify(presets));
  }, [presets]);

  const addPreset = (presetData) => {
    const newPreset = { 
      ...presetData, 
      id: uuidv4(), 
      favorite: false,
      voiceNo: presetData.voiceNo !== undefined ? presetData.voiceNo : null 
    };
    setPresets(prev => [...prev, newPreset]);
  };

  const updatePreset = (id, updatedData) => {
    setPresets(prev => prev.map(p => p.id === id ? { ...p, ...updatedData } : p));
  };

  const deletePreset = (id) => {
    setPresets(prev => prev.filter(p => p.id !== id));
  };

  const toggleFavorite = (id) => {
    setPresets(prev => prev.map(p => p.id === id ? { ...p, favorite: !p.favorite } : p));
  };

  const loadDefaultPresets = (overwrite = false) => {
    if (overwrite) {
      setPresets(DEFAULT_PRESETS);
    } else {
      setPresets(prev => {
        const existingNames = new Set(prev.map(p => p.name.toLowerCase()));
        const newPresets = DEFAULT_PRESETS.filter(p => !existingNames.has(p.name.toLowerCase()));
        return [...prev, ...newPresets];
      });
    }
  };

  const exportPresets = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(presets));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href",     dataStr);
    downloadAnchorNode.setAttribute("download", "midi_presets.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const importPresets = (file) => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const imported = JSON.parse(e.target.result);
          if (Array.isArray(imported)) {
            const cleanImported = imported.map(p => ({
              ...p,
              id: p.id || uuidv4(),
              favorite: !!p.favorite,
              voiceNo: p.voiceNo !== undefined ? p.voiceNo : null
            }));
            setPresets(prev => [...prev, ...cleanImported]);
            resolve(true);
          } else {
            reject(new Error("Invalid JSON format. Expected an array of presets."));
          }
        } catch (err) {
          reject(err);
        }
      };
      reader.onerror = () => reject(new Error("Failed to read file"));
      reader.readAsText(file);
    });
  };

  return {
    presets,
    addPreset,
    updatePreset,
    deletePreset,
    toggleFavorite,
    loadDefaultPresets,
    exportPresets,
    importPresets
  };
}